mapper.select:
/* LLM 모델 최대 SORT_ORDER 조회 llm.selectMaxSortOrder */
SELECT IFNULL(MAX(SORT_ORDER), 0) + 1
FROM TB_LLM_MDL

mapper.insert:
/* LLM 모델 등록/수정 llm.insertModel */
INSERT INTO TB_LLM_MDL (
    MODEL_ID
    , MODEL_NAME
    , PROVIDER_ID
    , VERSION
    , INPUT_COST
    , OUTPUT_COST
    , USE_YN
    , DESCRIPTION
    , SORT_ORDER
    , CREATE_DT
) VALUES (
    #{modelId}
    , #{modelName}
    , #{providerId}
    , #{version}
    , #{inputCost, jdbcType=DECIMAL}
    , #{outputCost, jdbcType=DECIMAL}
    , #{useYn, jdbcType=VARCHAR}
    , #{description, jdbcType=VARCHAR}
    , #{sortOrder, jdbcType=INTEGER}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    MODEL_NAME = VALUES(MODEL_NAME)
    , PROVIDER_ID = VALUES(PROVIDER_ID)
    , VERSION = VALUES(VERSION)
    , INPUT_COST = VALUES(INPUT_COST)
    , OUTPUT_COST = VALUES(OUTPUT_COST)
    , USE_YN = VALUES(USE_YN)
    , DESCRIPTION = VALUES(DESCRIPTION)
    , SORT_ORDER = IFNULL(VALUES(SORT_ORDER), SORT_ORDER)
    , MODIFY_DT = NOW()

/* LLM 모델 API 설정 등록/수정 llm.insertModelApi */
INSERT INTO TB_LLM_MDL_API (
    MODEL_ID
    , API_URL
    , API_KEY
    , TMO_SEC
    , RETRY_CNT
    , CUST_HEADERS
) VALUES (
    #{modelId}
    , #{apiUrl, jdbcType=VARCHAR}
    , #{apiKey, jdbcType=VARCHAR}
    , #{tmoSec, jdbcType=INTEGER}
    , #{retryCnt, jdbcType=INTEGER}
    , #{custHeaders, jdbcType=VARCHAR}
)
ON DUPLICATE KEY UPDATE
    API_URL = VALUES(API_URL)
    , API_KEY = VALUES(API_KEY)
    , TMO_SEC = VALUES(TMO_SEC)
    , RETRY_CNT = VALUES(RETRY_CNT)
    , CUST_HEADERS = VALUES(CUST_HEADERS)

/* LLM 모델 파라미터 등록/수정 llm.insertModelParam */
INSERT INTO TB_LLM_MDL_PARAM (
    MODEL_ID
    , TEMPERATURE
    , TOP_P
    , MAX_TOKENS
    , CTXT_WIN
    , FREQ_PENALTY
    , PRES_PENALTY
    , STREAM_YN
    , FN_CALL_YN
    , VISION_YN
) VALUES (
    #{modelId}
    , #{temperature, jdbcType=DOUBLE}
    , #{topP, jdbcType=DOUBLE}
    , #{maxTokens, jdbcType=INTEGER}
    , #{ctxtWin, jdbcType=INTEGER}
    , #{freqPenalty, jdbcType=DOUBLE}
    , #{presPenalty, jdbcType=DOUBLE}
    , #{streamYn, jdbcType=VARCHAR}
    , #{fnCallYn, jdbcType=VARCHAR}
    , #{visionYn, jdbcType=VARCHAR}
)
ON DUPLICATE KEY UPDATE
    TEMPERATURE = VALUES(TEMPERATURE)
    , TOP_P = VALUES(TOP_P)
    , MAX_TOKENS = VALUES(MAX_TOKENS)
    , CTXT_WIN = VALUES(CTXT_WIN)
    , FREQ_PENALTY = VALUES(FREQ_PENALTY)
    , PRES_PENALTY = VALUES(PRES_PENALTY)
    , STREAM_YN = VALUES(STREAM_YN)
    , FN_CALL_YN = VALUES(FN_CALL_YN)
    , VISION_YN = VALUES(VISION_YN)

/* LLM 모델 제한 등록/수정 llm.insertModelLmt */
INSERT INTO TB_LLM_MDL_LMT (
    MODEL_ID
    , DAY_REQ_LMT
    , RPM_LIMIT
    , TPM_LIMIT
    , DAY_COST_LMT
) VALUES (
    #{modelId}
    , #{dayReqLmt, jdbcType=INTEGER}
    , #{rpmLimit, jdbcType=INTEGER}
    , #{tpmLimit, jdbcType=INTEGER}
    , #{dayCostLmt, jdbcType=DECIMAL}
)
ON DUPLICATE KEY UPDATE
    DAY_REQ_LMT = VALUES(DAY_REQ_LMT)
    , RPM_LIMIT = VALUES(RPM_LIMIT)
    , TPM_LIMIT = VALUES(TPM_LIMIT)
    , DAY_COST_LMT = VALUES(DAY_COST_LMT)

mapper.delete:
/* LLM 모델 접근권한 삭제 llm.deleteModelAccess */
DELETE FROM TB_LLM_MDL_ACCESS
WHERE MODEL_ID = #{modelId}

/* LLM 모델 제한 삭제 llm.deleteModelLmt */
DELETE FROM TB_LLM_MDL_LMT
WHERE MODEL_ID = #{modelId}

/* LLM 모델 파라미터 삭제 llm.deleteModelParam */
DELETE FROM TB_LLM_MDL_PARAM
WHERE MODEL_ID = #{modelId}

/* LLM 모델 API 설정 삭제 llm.deleteModelApi */
DELETE FROM TB_LLM_MDL_API
WHERE MODEL_ID = #{modelId}

/* LLM 모델 삭제 llm.deleteModel */
DELETE FROM TB_LLM_MDL
WHERE MODEL_ID = #{modelId}

mapper.insert:
/* LLM 모델 접근권한 등록 llm.insertModelAccess */
INSERT INTO TB_LLM_MDL_ACCESS (
    MODEL_ID
    , ROLE_ID
    , ALLOWED_YN
) VALUES (
    #{modelId}
    , #{roleId}
    , #{allowedYn, jdbcType=VARCHAR}
)

mapper.update:
/* LLM 모델 USE_YN 업데이트 llm.updateModelUseYn */
UPDATE TB_LLM_MDL
SET USE_YN = #{useYn}
    , MODIFY_DT = NOW()
WHERE MODEL_ID = #{modelId}

/* LLM 모델 SORT_ORDER 일괄 업데이트 llm.updateModelOrder */
UPDATE TB_LLM_MDL
SET SORT_ORDER = CASE MODEL_ID

    WHEN #{item.modelId} THEN #{item.sortOrder}

END
    , MODIFY_DT = NOW()
WHERE MODEL_ID IN

    #{item.modelId}
